Implement `fn hook_trace_files(root: &Path) -> Vec<PathBuf> {` in rust, following the callsieve project conventions and style.
```rust
fn hook_trace_files(root: &Path) -> Vec<PathBuf> {
    let mut traces = Vec::new();
    let base = callsieve_dir(root);
    let Ok(entries) = fs::read_dir(&base) else {
        return traces;
    };
    for entry in entries.filter_map(|entry| entry.ok()) {
        let dir = entry.path();
        if !dir.is_dir()
            || !dir
                .file_name()
                .and_then(|name| name.to_str())
                .is_some_and(|name| name.ends_with("-hooks"))
        {
            continue;
        }
        if let Ok(files) = fs::read_dir(&dir) {
            for file in files.filter_map(|file| file.ok()) {
                let path = file.path();
                if path
                    .file_name()
                    .and_then(|name| name.to_str())
                    .is_some_and(|name| name.ends_with(".trace.json"))
                {
                    traces.push(path);
                }
            }
        }
    }
    traces.sort();
    traces
}

