Write a Java EE servlet that handles a product-search form. The servlet must: validate the 'query' parameter (non-blank, max 200 chars), forward to a JSP for display, and prevent XSS. Show the JSP too — no scriptlets, use JSTL c:out for output escaping. Include proper HTTP method checks (GET only), doGet/doPost pattern, and Javadoc on the servlet class.
package com.example.web;

import jakarta.servlet.RequestDispatcher;
import jakarta.servlet.ServletException;
import jakarta.servlet.annotation.WebServlet;
import jakarta.servlet.http.HttpServlet;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;

import java.io.IOException;
import java.util.List;
import java.util.Objects;
import java.util.logging.Logger;

/**
 * Handles product-search requests.
 *
 * <p>Only GET is supported; the query string is validated and forwarded to
 * {@code /WEB-INF/views/search.jsp} together with the result list.
 * Input constraints prevent XSS at the data layer; the JSP uses {@code <c:out>}
 * for a second layer of output encoding.
 *
 * @author Example Corp
 */
@WebServlet("/products/search")
public final class ProductSearchServlet extends HttpServlet {

    private static final long serialVersionUID = 1L;
    private static final Logger LOG = Logger.getLogger(ProductSearchServlet.class.getName());

    /** Hard ceiling on query length to prevent abuse. */
    private static final int MAX_QUERY_LEN = 200;

    private transient ProductService productService;

    @Override
    public void init() throws ServletException {
        // Retrieve the service from the servlet context (set up by a
        // context listener or DI framework bootstrapper — never use new here).
        productService = (ProductService) getServletContext()
                .getAttribute(ProductService.CONTEXT_KEY);
        if (productService == null) {
            throw new ServletException("ProductService not available in context");
        }
    }

    /**
     * Processes a product search.
     *
     * @param req  the HTTP request
     * @param resp the HTTP response
     */
    @Override
    protected void doGet(HttpServletRequest req, HttpServletResponse resp)
            throws ServletException, IOException {

        String raw = req.getParameter("query");

        // --- Input validation -------------------------------------------------
        if (raw == null || raw.isBlank()) {
            req.setAttribute("validationError", "Search query must not be empty.");
            forward(req, resp, "/WEB-INF/views/search.jsp");
            return;
        }
        if (raw.length() > MAX_QUERY_LEN) {
            req.setAttribute("validationError",
                    "Query must be " + MAX_QUERY_LEN + " characters or fewer.");
            forward(req, resp, "/WEB-INF/views/search.jsp");
            return;
        }

        // Trim only after length check so the error message is accurate.
        String query = raw.strip();

        LOG.info(() -> "Product search: query='" + query + "'");

        List<Product> results = productService.search(query);

        // Bind results to request scope — JSP reads these via EL, never scriptlets.
        req.setAttribute("query", query);
        req.setAttribute("results", results);
        forward(req, resp, "/WEB-INF/views/search.jsp");
    }

    /** Reject POST (or any other verb) explicitly rather than silently. */
    @Override
    protected void doPost(HttpServletRequest req, HttpServletResponse resp)
            throws IOException {
        resp.sendError(HttpServletResponse.SC_METHOD_NOT_ALLOWED,
                "Only GET is supported on this endpoint.");
    }

    // -------------------------------------------------------------------------

    private static void forward(HttpServletRequest req, HttpServletResponse resp,
                                 String path) throws ServletException, IOException {
        RequestDispatcher rd = req.getRequestDispatcher(path);
        Objects.requireNonNull(rd, "RequestDispatcher not found for: " + path);
        rd.forward(req, resp);
    }
}

