Implement `fn zed_project_settings_mergeable(root: &Path) -> bool {` in rust, following the callsieve project conventions and style.
```rust
fn zed_project_settings_mergeable(root: &Path) -> bool {
    let path = root.join(".zed/settings.json");
    if !path.exists() {
        return true;
    }
    fs::read_to_string(&path)
        .ok()
        .and_then(|content| serde_json::from_str::<serde_json::Value>(&content).ok())
        .is_some_and(|value| value.is_object())
}

