fn push_rehearsal_check(
    checks: &mut Vec<ProofRehearsalCheck>,
    check: &str,
    path: &str,
    passed: bool,
    pass_message: &str,
    fail_message: &str,
) {
    checks.push(ProofRehearsalCheck {
        check: check.to_string(),
        path: path.to_string(),
        status: if passed { "pass" } else { "fail" }.to_string(),
