Use Redis from Rust for caching with sensible patterns.
```rust
use redis::AsyncCommands;
async fn get_cached(con:&mut redis::aio::MultiplexedConnection, key:&str) -> redis::RedisResult<Option<String>> {
    con.get(key).await
}
async fn set_cached(con:&mut redis::aio::MultiplexedConnection, key:&str, val:&str) -> redis::RedisResult<()> {
    con.set_ex(key, val, 300).await   // TTL so the cache can't go stale forever
}
```
Always set a TTL (`SET EX`), use a multiplexed async connection (not one-per-request), and treat the cache as best-effort — fall back to the DB on miss/error, never block on Redis.

