Implement `fn trim_offset(src: &str, mut offset: u16) -> &str {` in rust (from reflow.rs), following this project's conventions and style.
```rust
fn trim_offset(src: &str, mut offset: u16) -> &str {
    let mut start = 0;
    for c in UnicodeSegmentation::graphemes(src, true) {
        let w = c.cell_width();
        if w <= offset {
            offset -= w;
            start += c.len();
        } else {
            break;
        }
    }
    #[expect(clippy::string_slice)] // Is safe as it comes from UnicodeSegmentation
    &src[start..]
}

